import React from 'react';
import Card from '../components/Card';
import MonthlyComparison from '../components/MonthlyComparison';

const BusinessDataNew: React.FC = () => {
  return (
    <div className="max-w-full mx-auto px-4 sm:px-6 lg:px-32 py-8">
      <Card>
        <div className="py-8">
          <h1 className="text-2xl font-bold text-gray-900 mb-2 text-center">
            Business Data Analytics
          </h1>
          <p className="text-gray-600 text-center">
            Comprehensive business performance analytics and insights
          </p>
        </div>
      </Card>
      
      <div className="mt-8">
        <Card>
          <div className="py-16 text-center">
            <h2 className="text-xl font-semibold text-gray-700 mb-4">
              📊 Analytics Dashboard
            </h2>
            <p className="text-gray-500">
              This is a completely fresh, clean business data page with no tables or data entry components.
            </p>
          </div>
        </Card>
      </div>
    </div>
  );
};

export default BusinessDataNew;
